#include<bits/stdc++.h>
using namespace std;
const long long mod=(1ll<<31)-1,N=1010;
int n,m;
vector<pair<int,int>> mp[N];
int dis[N];
bool vis[N];
void dijkstra()
{
    priority_queue<pair<int,int>> q;
    q.push(make_pair(0,1));
    memset(dis,0x3f,sizeof(dis));
    dis[1]=0;
    while(!q.empty())
    {
        int t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=1;
        for(auto i:mp[t])
        {
            int v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push(make_pair(-dis[v],v));
            }
        }
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    dijkstra();
    long long ans=1;
    for(int i=1;i<=n;i++)
    {
        int cnt=0;
        for(auto j:mp[i])
        {
            int v=j.first,val=j.second;
            if(dis[i]==dis[v]+val)
            {
                cnt++;
            }
        }
        ans*=max(1,cnt);
        ans%=mod;
    }
    printf("%lld",ans);
    return 0;
}
